    public int[] addNegabinary(int[] arr1, int[] arr2) {
        var a = toTen(arr1);
        var b = toTen(arr2);
        System.out.println(a);
        System.out.println(b);
        return baseNeg2(a + b);
    }


    long toTen(int[] arr) {
        int len = arr.length;
        int k = 0;

        long ret = 0;

        for (int i = len - 1; i >= 0; i--) {
            ret += arr[i] * Math.pow(-2, k++);
        }

        return ret;
    }

    int[] baseNeg2(long value) {
        if (value == 0) return new int[]{0};
        StringBuilder sb = new StringBuilder();
        int k = 1;
        while (value != 0) {
            if (value % 2 != 0) {
                sb.append(1);
                value -= k;
            } else {
                sb.append(0);
            }
            k *= -1;
            value /= 2;
        }
        char[] arr = sb.reverse().toString().toCharArray();
        int[] ans = new int[arr.length];
        for (int i = 0; i < arr.length; i++) {
            ans[i] = Character.getNumericValue(arr[i]);
        }
        return ans;
    }

